const PROCESSING_FEE_G = 5;
const BLOCK_SIZE = 3;
const BLOCK_PRICE_G = 60;
const COMPONENT_UNIT_PRICE_G = 25;

type Item = { type: string };
type Scenario = {
  steps: Array<{ op: "quote"; items: Item[] }>;
};

const basePremiumForType = (count: number): number =>
  count === BLOCK_SIZE ? BLOCK_PRICE_G : count * COMPONENT_UNIT_PRICE_G;

const quotePremium = (items: Item[]): number => {
  const countsByType = new Map<string, number>();
  for (const item of items) {
    countsByType.set(item.type, (countsByType.get(item.type) ?? 0) + 1);
  }
  let base = 0;
  for (const count of countsByType.values()) {
    base += basePremiumForType(count);
  }
  const withFirstInsurance = Math.ceil((base * 11) / 10);
  return withFirstInsurance + PROCESSING_FEE_G;
};

